def classify_intent(query: str) -> str:
    # Simple semantic rule router
    q = query.lower()
    if any(k in q for k in ["pay", "invoice", "card", "billing"]):
        return "billing_agent"
    if any(k in q for k in ["bug", "broken", "error", "crash"]):
        return "tech_agent"
    return "general_agent"
